import lxml.etree as et
from lxml.valid import Validate, relayed_error

def validate_and_read_xml(xml_file):
    valid = Validate(relaxng='rng/your_xsd_file.rng')
    try:
        tree = et.parse(xml_file)
        valid(etree_document=tree.getroottree())
        return tree.getroot()
    except relayed_error as e:
        print("Invalid XML:", e.message)
        return None